import numpy as np

def lu_to_cholesky(L: list[list[float]], U: list[list[float]]) -> list[list[float]]:
    U_arr = np.array(U, dtype=float)
    n = U_arr.shape[0]
    R = np.zeros_like(U_arr)
    for i in range(n):
        scale = np.sqrt(U_arr[i, i])
        R[i, i:] = U_arr[i, i:] / scale
    return R.tolist()
